35: 
36: /**
37:  * Messaging with AMQP protocol using Apache QPid Client.
38:  */
39: @Component("amqp")
40: public class AMQPComponent extends JmsComponent {
41: 
42:     private static final Logger LOG = LoggerFactory.getLogger(AMQPComponent.class);
43: 
44:     public static final String AMQP_DEFAULT_HOST = "localhost";
45:     public static final int AMQP_DEFAULT_PORT = 5672;
46: 
47:     @Metadata(description = "Remote URL to broker. The URL is used to setup connection factory and is broker specific (such as ActiveMQ).")
48:     private String brokerUrl;
49:     @Metadata(description = "The host name or IP address of the computer that hosts the AMQP Broker.")
50:     private String host;
51:     @Metadata(description = "The port number on which the AMPQ Broker listens.")
52:     private Integer port;
53:     @Metadata(description = "Whether to configure topics with a `topic://` prefix.")
54:     private Boolean useTopicPrefix;
55:     @Metadata(description = "Whether to enable SSL when connecting to the AMQP Broker.")
56:     private Boolean useSsl;
57:     @Metadata(description = "The SSL keystore location.")
58:     private String keyStoreLocation;
59:     @Metadata(defaultValue = "JKS", description = "The SSL keystore type.")
60:     private String keyStoreType = "JKS";
61:     @Metadata(label = "security", secret = true, description = "The SSL keystore password.")
62:     private String keyStorePassword;
63:     @Metadata(description = "The SSL truststore location.")
64:     private String trustStoreLocation;
65:     @Metadata(defaultValue = "JKS", description = "The SSL truststore type.")
66:     private String trustStoreType = "JKS";
67:     @Metadata(label = "security", secret = true, description = "The SSL truststore password.")
68:     private String trustStorePassword;
69: 
70:     // Constructors
71: 
72:     public AMQPComponent() {
73:     }
74: 
75:     public AMQPComponent(JmsConfiguration configuration) {
76:         super(configuration);
77:     }
78: 
79:     public AMQPComponent(CamelContext context) {
80:         super(context);
81:     }
82: 
83:     public AMQPComponent(ConnectionFactory connectionFactory) {
84:         this();
85:         getConfiguration().setConnectionFactory(connectionFactory);
86:     }
87: 
88:     // Factory methods
89: 
90:     public static AMQPComponent amqpComponent(String uri) {
91:         JmsConnectionFactory connectionFactory = new JmsConnectionFactory(uri);
92:         connectionFactory.setTopicPrefix("topic://");
93:         return new AMQPComponent(connectionFactory);
94:     }
95: 
96:     public static AMQPComponent amqpComponent(String uri, String username, String password) {
97:         JmsConnectionFactory connectionFactory = new JmsConnectionFactory(username, password, uri);
98:         connectionFactory.setTopicPrefix("topic://");
99:         return new AMQPComponent(connectionFactory);
100:     }
101: 
102:     // Life-cycle
103: 
104:     @Override
105:     protected void doInit() throws Exception {
106:         if (brokerUrl != null) {
107:             JmsConnectionFactory connectionFactory
108:                     = new JmsConnectionFactory(brokerUrl);
109:             if (useTopicPrefix != Boolean.FALSE) {
110:                 connectionFactory.setTopicPrefix("topic://");
111:             }
112:             getConfiguration().setConnectionFactory(connectionFactory);
113:         } else if (host != null || port != null || getUsername() != null || getPassword() != null || useTopicPrefix != null
114:                 || useSsl != null) {
115:             StringBuilder sb = new StringBuilder();
116:             sb.append(useSsl == Boolean.TRUE ? "amqps://" : "amqp://");
117:             sb.append(host == null ? AMQP_DEFAULT_HOST : host).append(":").append(port == null ? AMQP_DEFAULT_PORT : port);
118:             if (useSsl == Boolean.TRUE) {
119:                 sb.append("?transport.trustStoreLocation=").append(trustStoreLocation == null ? "" : trustStoreLocation);
120:                 sb.append("&transport.trustStoreType=").append(trustStoreType);
121:                 sb.append("&transport.trustStorePassword=").append(trustStorePassword == null ? "" : trustStorePassword);
122:                 sb.append("&transport.keyStoreLocation=").append(keyStoreLocation == null ? "" : keyStoreLocation);
123:                 sb.append("&transport.keyStoreType=").append(keyStoreType);
124:                 sb.append("&transport.keyStorePassword=").append(keyStorePassword == null ? "" : keyStorePassword);
125:             }
126:             JmsConnectionFactory connectionFactory
127:                     = new JmsConnectionFactory(getUsername(), getPassword(), sb.toString());
128:             if (useTopicPrefix != Boolean.FALSE) {
129:                 connectionFactory.setTopicPrefix("topic://");
130:             }
131:             getConfiguration().setConnectionFactory(connectionFactory);
132:         } else {
133:             Set<AMQPConnectionDetails> connectionDetails
134:                     = getCamelContext().getRegistry().findByType(AMQPConnectionDetails.class);
135:             if (connectionDetails.size() == 1) {
136:                 LOG.warn("Using AMQPConnectionDetails is deprecated");
137:                 AMQPConnectionDetails details = connectionDetails.iterator().next();
138:                 JmsConnectionFactory connectionFactory
139:                         = new JmsConnectionFactory(details.username(), details.password(), details.uri());
140:                 if (details.setTopicPrefix()) {
141:                     connectionFactory.setTopicPrefix("topic://");
142:                 }
143:                 getConfiguration().setConnectionFactory(connectionFactory);
144:             }
145:         }
146:         super.doInit();
147:     }
148: 
149:     @Override
150:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
151:         JmsEndpoint endpoint = (JmsEndpoint) super.createEndpoint(uri, remaining, parameters);
152:         endpoint.setBinding(new AMQPJmsBinding(endpoint));
153:         return endpoint;
154:     }
155: 
156:     /**
157:      * Factory method to create the default configuration instance
158:      *
159:      * @return a newly created configuration object which can then be further customized
160:      */
